#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long g = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &x);
            g = (i == 0) ? x : gcd_ll(g, x);
        }
        long long ans = g * (long long)N;
        printf("%lld\n", ans);
    }
    return 0;
}

