let idx = 0;
const T = input[idx++];
let results = [];
function gcd(a, b) {
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return a;
}
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  let g = 0;
  for (let i = 0; i < N; ++i) {
    const x = input[idx++];
    g = i === 0 ? x : gcd(g, x);
  }
  results.push(String(g * N));
}
